target:
:root {
  --bg-dark: #050E0B; /* Deep Forest Black-Green */
  --bg-card: rgba(10, 25, 20, 0.6);
  --border-glass: rgba(255, 255, 255, 0.08);

  /* Forest Accents */
  --accent-green-bright: #39FF14; /* Neon Green */
  --accent-teal: #00F5D4;
  --accent-orange: #FF9F1C;
  --accent-pink: #FF007F;
  --accent-purple: #9D4EDD;
  --accent-forest: #1E5128;

  --text-primary: #F3F4F6;
  --text-secondary: #A3B899; /* Sage green secondary text */

  --font-heading: 'Syne', system-ui, sans-serif;
  --font-body: 'DM Sans', system-ui, sans-serif;

  --shadow-neon-green: 0 0 15px rgba(57, 255, 20, 0.3);
  --shadow-neon-teal: 0 0 15px rgba(0, 245, 212, 0.35);
  --shadow-neon-orange: 0 0 15px rgba(255, 159, 28, 0.35);
  --shadow-neon-pink: 0 0 15px rgba(255, 0, 127, 0.35);
  --shadow-neon-purple: 0 0 15px rgba(157, 78, 221, 0.35);
}

